"use client";
import {
  useCallback,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { TooltipProvider } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import {
  CodeBlockProvider,
} from "./hooks/use-code-block-context";
import { useControllableState } from "./hooks/use-controllable-state";
import { useCopyToClipboard } from "./hooks/use-copy-to-clipboard";
import { resolveLang } from "./lib/lang-resolution";
import { joinTerminalLines } from "./lib/terminal-utils";
import { CodeBlockBodyEdit } from "./parts/code-block-body-edit";
import { CodeBlockBodyTerminal } from "./parts/code-block-body-terminal";
import { CodeBlockBodyView } from "./parts/code-block-body-view";
import { CodeBlockCopyButton } from "./parts/code-block-copy-button";
import { CodeBlockDownloadButton } from "./parts/code-block-download-button";
import { CodeBlockExpandButton } from "./parts/code-block-expand-button";
import { CodeBlockExpandModal } from "./parts/code-block-expand-modal";
import { CodeBlockFooter } from "./parts/code-block-footer";
import { CodeBlockHeader } from "./parts/code-block-header";
import { CodeBlockTrafficLights } from "./parts/code-block-traffic-lights";
import { CodeBlockWrapButton } from "./parts/code-block-wrap-button";
import {
  DEFAULT_LABELS,
  type CodeBlockHandle,
  type CodeBlockProps,
} from "./types";

const DEFAULT_THEMES = {
  light: "github-light",
  dark: "github-dark-default",
} as const;

export function CodeBlock(props: CodeBlockProps) {
  const {
    value: valueProp,
    defaultValue,
    lines,
    lang: langProp,
    filename,
    filenameToLang,
    mode = "view",
    readOnly = false,
    streaming = false,
    onChange,
    onSave,
    tabSize = 4,
    editorExtensions,
    header = true,
    showLanguage = true,
    showCopy = true,
    showExpand = false,
    showWrap = false,
    showDownload = false,
    showTrafficLights = false,
    actions,
    renderHeader,
    renderExpandModal,
    footer,
    showLineNumbers,
    wrap: wrapProp,
    highlightedLines,
    annotations,
    renderAnnotation,
    maxLines,
    expanded: expandedProp,
    defaultExpanded,
    onExpandedChange,
    onWrapChange,
    onLineClick,
    onCopy,
    onDownload,
    themes,
    maxHeight,
    emptyMessage,
    className,
    style,
    ariaLabel,
    labels: labelsProp,
    ref,
  } = props;

  // Resolved values
  const labels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...(labelsProp ?? {}) }),
    [labelsProp],
  );
  const themesResolved = themes ?? DEFAULT_THEMES;
  const lang = useMemo(
    () => resolveLang(langProp, filename, filenameToLang),
    [langProp, filename, filenameToLang],
  );

  const lineDerivedValue = useMemo(() => {
    if (mode === "terminal" && lines) return joinTerminalLines(lines);
    return undefined;
  }, [mode, lines]);

  // Controlled/uncontrolled value for edit mode.
  const [editValue, setEditValueInternal] = useControllableState<string>({
    prop: mode === "edit" ? valueProp : undefined,
    defaultProp: defaultValue ?? valueProp ?? "",
    onChange: (next) => onChange?.({ value: next }),
  });

  const displayValue =
    mode === "edit"
      ? editValue
      : lineDerivedValue !== undefined
        ? lineDerivedValue
        : (valueProp ?? "");

  // Wrap state (controlled or local)
  const [wrap, setWrapInternal] = useControllableState<"wrap" | "scroll">({
    prop: wrapProp,
    defaultProp: wrapProp ?? "scroll",
    onChange: (next) => onWrapChange?.({ wrap: next }),
  });

  // Expanded (collapse) state
  const [expanded, setExpandedInternal] = useControllableState<boolean>({
    prop: expandedProp,
    defaultProp: defaultExpanded ?? false,
    onChange: (next) => onExpandedChange?.({ expanded: next }),
  });

  const [modalOpen, setModalOpen] = useState(false);

  // Line numbers default per mode
  const resolvedShowLineNumbers =
    showLineNumbers !== undefined
      ? showLineNumbers
      : mode === "edit"
        ? true
        : false;

  // Copy
  const { copy: copyToClipboard, copied, failed: copyFailed } = useCopyToClipboard();
  const handleCopy = useCallback(async () => {
    const ok = await copyToClipboard(displayValue);
    if (ok) onCopy?.({ value: displayValue });
    return ok;
  }, [copyToClipboard, displayValue, onCopy]);

  // Download
  const handleDownload = useCallback(() => {
    const resolvedFilename = filename ?? `code.${lang === "plaintext" ? "txt" : lang}`;
    if (onDownload) {
      onDownload({ value: displayValue, filename: resolvedFilename });
      return;
    }
    if (typeof window === "undefined") return;
    try {
      const blob = new Blob([displayValue], { type: "text/plain;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = resolvedFilename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch {
      // Soft-fail; download is best-effort.
    }
  }, [displayValue, filename, lang, onDownload]);

  // Imperative handle wired to body refs
  const editorImperativeRef = useRef<{
    focus: () => void;
    getValue: () => string;
  } | null>(null);

  const handle = useMemo<CodeBlockHandle>(
    () => ({
      copy: handleCopy,
      focus: () => editorImperativeRef.current?.focus(),
      getValue: () =>
        mode === "edit"
          ? (editorImperativeRef.current?.getValue() ?? editValue)
          : displayValue,
      scrollToLine: () => {
        // v0.1.0: best-effort no-op; reserved for v0.2 CodeMirror integration.
      },
    }),
    [handleCopy, displayValue, editValue, mode],
  );

  useImperativeHandle(ref, () => handle, [handle]);

  // Context value
  const ctxValue = useMemo(
    () => ({
      value: displayValue,
      filename,
      lang,
      resolvedLang: lang,
      mode,
      streaming,
      wrap,
      showLineNumbers: resolvedShowLineNumbers,
      expanded,
      setExpanded: setExpandedInternal,
      setWrap: setWrapInternal,
      modalOpen,
      setModalOpen,
      labels,
      copy: handleCopy,
      copied,
      copyFailed,
      download: handleDownload,
      handle,
    }),
    [
      displayValue,
      filename,
      lang,
      mode,
      streaming,
      wrap,
      resolvedShowLineNumbers,
      expanded,
      setExpandedInternal,
      setWrapInternal,
      modalOpen,
      labels,
      handleCopy,
      copied,
      copyFailed,
      handleDownload,
      handle,
    ],
  );

  // Resolved aria-label
  const resolvedAriaLabel =
    ariaLabel ??
    (filename
      ? `Code block — ${filename}`
      : `Code block — ${lang === "plaintext" ? "text" : lang}`);

  const body = (() => {
    if (mode === "edit") {
      return (
        <CodeBlockBodyEdit
          value={editValue}
          lang={lang}
          readOnly={readOnly}
          wrap={wrap}
          tabSize={tabSize}
          showLineNumbers={resolvedShowLineNumbers}
          onChange={(v) => setEditValueInternal(v)}
          onSave={onSave ? (v) => onSave({ value: v }) : undefined}
          editorExtensions={editorExtensions}
          maxHeight={maxHeight}
          registerImperative={(h) => {
            editorImperativeRef.current = h;
          }}
        />
      );
    }
    if (mode === "terminal") {
      return (
        <CodeBlockBodyTerminal
          value={valueProp ?? ""}
          lines={lines}
          wrap={wrap}
          streaming={streaming}
          emptyMessage={emptyMessage}
          maxHeight={maxHeight}
        />
      );
    }
    return (
      <CodeBlockBodyView
        value={valueProp ?? ""}
        lang={lang}
        themes={themesResolved}
        highlightedLines={highlightedLines}
        annotations={annotations}
        renderAnnotation={renderAnnotation}
        showLineNumbers={resolvedShowLineNumbers}
        wrap={wrap}
        streaming={streaming}
        expanded={expanded}
        maxLines={maxLines}
        emptyMessage={emptyMessage}
        maxHeight={maxHeight}
        onLineClick={onLineClick}
      />
    );
  })();

  // Header — either the default orchestrator or the renderHeader slot.
  const headerNode = (() => {
    if (header === false) return null;
    if (renderHeader) {
      const headerCtx = {
        filename,
        lang,
        copyButton: showCopy ? <CodeBlockCopyButton /> : (null as never),
        expandButton: showExpand ? <CodeBlockExpandButton /> : null,
        wrapButton: showWrap ? <CodeBlockWrapButton /> : null,
        downloadButton: showDownload ? <CodeBlockDownloadButton /> : null,
        trafficLights: showTrafficLights ? <CodeBlockTrafficLights /> : null,
        actions: actions ?? null,
      };
      return <>{renderHeader(headerCtx)}</>;
    }
    return (
      <CodeBlockHeader
        showLanguage={showLanguage}
        showCopy={showCopy}
        showExpand={showExpand}
        showWrap={showWrap}
        showDownload={showDownload}
        showTrafficLights={showTrafficLights}
        actions={actions}
      />
    );
  })();

  // Modal body — same instance with expand off + maxLines undefined.
  const expandedInner = (
    <CodeBlock
      {...props}
      header={true}
      showExpand={false}
      maxLines={undefined}
      maxHeight={undefined}
      className="rounded-none border-0 shadow-none"
    />
  );

  const modalNode = (() => {
    if (!showExpand) return null;
    if (renderExpandModal) {
      return renderExpandModal({
        open: modalOpen,
        onOpenChange: setModalOpen,
        code: expandedInner,
      });
    }
    return (
      <CodeBlockExpandModal
        open={modalOpen}
        onOpenChange={setModalOpen}
        title={filename ?? lang}
      >
        {expandedInner}
      </CodeBlockExpandModal>
    );
  })();

  return (
    <CodeBlockProvider value={ctxValue}>
      <TooltipProvider delayDuration={300}>
        <section
          role="region"
          aria-label={resolvedAriaLabel}
          className={cn(
            "code-block group relative overflow-hidden rounded-lg border border-border/60 bg-card text-card-foreground shadow-sm",
            className,
          )}
          style={style}
        >
          {headerNode}
          {body}
          {footer ? <CodeBlockFooter>{footer}</CodeBlockFooter> : null}
        </section>
        {modalNode}
      </TooltipProvider>
    </CodeBlockProvider>
  );
}

CodeBlock.displayName = "CodeBlock";

export { CodeBlock } from "./code-block";
export { CodeBlockHeader } from "./parts/code-block-header";
export { CodeBlockFilename } from "./parts/code-block-filename";
export { CodeBlockLangPill } from "./parts/code-block-lang-pill";
export { CodeBlockCopyButton } from "./parts/code-block-copy-button";
export { CodeBlockExpandButton } from "./parts/code-block-expand-button";
export { CodeBlockWrapButton } from "./parts/code-block-wrap-button";
export { CodeBlockDownloadButton } from "./parts/code-block-download-button";
export { CodeBlockTrafficLights } from "./parts/code-block-traffic-lights";
export { useCodeBlock } from "./hooks/use-code-block-context";
export { resolveLang, FILENAME_TO_LANG_MAP } from "./lib/lang-resolution";
export type {
  CodeBlockProps,
  CodeBlockServerProps,
  CodeBlockHandle,
  CodeBlockMode,
  CodeBlockWrap,
  CodeBlockAnnotation,
  CodeBlockAnnotationType,
  CodeBlockLineRange,
  CodeBlockLabels,
  CodeBlockThemes,
  CodeBlockChangeArgs,
  CodeBlockCopyArgs,
  CodeBlockSaveArgs,
  CodeBlockDownloadArgs,
  CodeBlockLineClickArgs,
  CodeBlockExpandedChangeArgs,
  CodeBlockWrapChangeArgs,
  CodeBlockFilenameToLangArgs,
  CodeBlockHeaderContext,
  CodeBlockAnnotationRenderArgs,
  CodeBlockExpandModalContext,
  ShikiThemeObject,
  TerminalLine,
  TerminalLineKind,
} from "./types";

import type { CSSProperties, ReactNode, Ref } from "react";
import type { Extension } from "@codemirror/state";

// ─── Core enums ──────────────────────────────────────────────────────────────

export type CodeBlockMode = "view" | "edit" | "terminal";
export type CodeBlockWrap = "wrap" | "scroll";
export type CodeBlockAnnotationType = "info" | "warn" | "error";
export type TerminalLineKind = "input" | "output" | "error";

// ─── Value-shaped types ──────────────────────────────────────────────────────

export interface CodeBlockLineRange {
  from: number;
  to: number;
}

export interface TerminalLine {
  kind: TerminalLineKind;
  text: string;
}

export interface CodeBlockAnnotation {
  line: number;
  type: CodeBlockAnnotationType;
  message: string;
}

export type ShikiThemeObject = {
  name: string;
  type: "light" | "dark";
  [key: string]: unknown;
};

export interface CodeBlockThemes {
  light: string | ShikiThemeObject;
  dark: string | ShikiThemeObject;
}

// ─── Imperative handle ───────────────────────────────────────────────────────

export interface CodeBlockHandle {
  copy: () => Promise<boolean>;
  focus: () => void;
  getValue: () => string;
  scrollToLine: (line: number) => void;
}

// ─── Callback arg shapes (object-shape per F-cross-12) ───────────────────────

export interface CodeBlockChangeArgs {
  value: string;
}
export interface CodeBlockCopyArgs {
  value: string;
}
export interface CodeBlockSaveArgs {
  value: string;
}
export interface CodeBlockDownloadArgs {
  value: string;
  filename: string;
}
export interface CodeBlockLineClickArgs {
  line: number;
}
export interface CodeBlockExpandedChangeArgs {
  expanded: boolean;
}
export interface CodeBlockWrapChangeArgs {
  wrap: CodeBlockWrap;
}
export interface CodeBlockFilenameToLangArgs {
  filename: string;
}

// ─── Slot contexts ───────────────────────────────────────────────────────────

export interface CodeBlockHeaderContext {
  filename: string | undefined;
  lang: string;
  copyButton: ReactNode;
  expandButton: ReactNode | null;
  wrapButton: ReactNode | null;
  downloadButton: ReactNode | null;
  trafficLights: ReactNode | null;
  actions: ReactNode | null;
}

export interface CodeBlockAnnotationRenderArgs {
  annotation: CodeBlockAnnotation;
  defaultMarker: ReactNode;
}

export interface CodeBlockExpandModalContext {
  open: boolean;
  onOpenChange: (next: boolean) => void;
  code: ReactNode;
}

// ─── i18n labels ─────────────────────────────────────────────────────────────

export type CodeBlockLabels = Partial<{
  copy: string;
  copied: string;
  copyFailed: string;
  expand: string;
  wrap: string;
  download: string;
  showMore: string;
  showLess: string;
  streamingCursor: string;
  closeModal: string;
  emptyDefault: string;
}>;

export const DEFAULT_LABELS: Required<CodeBlockLabels> = {
  copy: "Copy code",
  copied: "Copied",
  copyFailed: "Copy failed — select and copy manually",
  expand: "Expand",
  wrap: "Toggle wrap",
  download: "Download",
  showMore: "Show all",
  showLess: "Show less",
  streamingCursor: "Streaming",
  closeModal: "Close",
  emptyDefault: "",
};

// ─── Top-level props (client variant) ────────────────────────────────────────

export interface CodeBlockProps {
  // Content
  value?: string;
  lines?: TerminalLine[];
  defaultValue?: string;

  // Language
  lang?: string;
  filename?: string;
  filenameToLang?: (args: CodeBlockFilenameToLangArgs) => string | undefined;

  // Mode
  mode?: CodeBlockMode;
  readOnly?: boolean;
  streaming?: boolean;

  // Edit
  onChange?: (args: CodeBlockChangeArgs) => void;
  onSave?: (args: CodeBlockSaveArgs) => void;
  tabSize?: number;
  editorExtensions?: Extension[];

  // Header
  header?: boolean;
  showLanguage?: boolean;
  showCopy?: boolean;
  showExpand?: boolean;
  showWrap?: boolean;
  showDownload?: boolean;
  showTrafficLights?: boolean;
  actions?: ReactNode;
  renderHeader?: (ctx: CodeBlockHeaderContext) => ReactNode;
  renderExpandModal?: (ctx: CodeBlockExpandModalContext) => ReactNode;

  // Footer
  footer?: ReactNode;

  // Body
  showLineNumbers?: boolean;
  wrap?: CodeBlockWrap;
  highlightedLines?: Array<number | CodeBlockLineRange>;
  annotations?: CodeBlockAnnotation[];
  renderAnnotation?: (args: CodeBlockAnnotationRenderArgs) => ReactNode;

  // Collapse
  maxLines?: number;
  expanded?: boolean;
  defaultExpanded?: boolean;
  onExpandedChange?: (args: CodeBlockExpandedChangeArgs) => void;

  // Wrap toggle
  onWrapChange?: (args: CodeBlockWrapChangeArgs) => void;

  // Line click
  onLineClick?: (args: CodeBlockLineClickArgs) => void;

  // Copy + download
  onCopy?: (args: CodeBlockCopyArgs) => void;
  onDownload?: (args: CodeBlockDownloadArgs) => void;

  // Theme
  themes?: CodeBlockThemes;

  // Sizing
  maxHeight?: number | string;

  // Empty
  emptyMessage?: string;

  // Polymorphic
  className?: string;
  style?: CSSProperties;

  // ARIA
  ariaLabel?: string;

  // i18n
  labels?: CodeBlockLabels;

  // Imperative handle
  ref?: Ref<CodeBlockHandle>;
}

// ─── RSC variant props (typed narrowing) ─────────────────────────────────────

/**
 * RSC-variant props. Compile-time narrowing of CodeBlockProps that removes
 * fields requiring client interactivity. TypeScript rejects mode='edit' and
 * streaming at compile time; the runtime guard in code-block.server.tsx is
 * a backstop for JS consumers.
 */
export type CodeBlockServerProps = Omit<
  CodeBlockProps,
  | "mode"
  | "readOnly"
  | "streaming"
  | "editorExtensions"
  | "onChange"
  | "onSave"
  | "tabSize"
  | "onWrapChange"
  | "showWrap"
  | "expanded"
  | "defaultExpanded"
  | "onExpandedChange"
  | "ref"
> & {
  mode?: "view" | "terminal";
};

"use client";
import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useCodeBlock } from "../hooks/use-code-block-context";
import { CodeBlockCopyButton } from "./code-block-copy-button";
import { CodeBlockDownloadButton } from "./code-block-download-button";
import { CodeBlockExpandButton } from "./code-block-expand-button";
import { CodeBlockFilename } from "./code-block-filename";
import { CodeBlockLangPill } from "./code-block-lang-pill";
import { CodeBlockTrafficLights } from "./code-block-traffic-lights";
import { CodeBlockWrapButton } from "./code-block-wrap-button";

export interface CodeBlockHeaderProps {
  showLanguage?: boolean;
  showCopy?: boolean;
  showExpand?: boolean;
  showWrap?: boolean;
  showDownload?: boolean;
  showTrafficLights?: boolean;
  actions?: ReactNode;
  className?: string;
}

export function CodeBlockHeader({
  showLanguage = true,
  showCopy = true,
  showExpand = false,
  showWrap = false,
  showDownload = false,
  showTrafficLights = false,
  actions,
  className,
}: CodeBlockHeaderProps) {
  const { filename, resolvedLang } = useCodeBlock();

  return (
    <div
      className={cn(
        "flex items-center gap-2 border-b border-border/60 bg-card/50 px-3 py-1.5",
        "min-h-9",
        className,
      )}
    >
      {showTrafficLights ? <CodeBlockTrafficLights className="mr-1" /> : null}
      <CodeBlockFilename filename={filename} />
      {filename && showLanguage && resolvedLang && resolvedLang !== "plaintext" ? (
        <span aria-hidden="true" className="text-muted-foreground/40">·</span>
      ) : null}
      {showLanguage ? <CodeBlockLangPill lang={resolvedLang} /> : null}
      <div className="flex-1" />
      {actions ? <div className="flex items-center gap-1">{actions}</div> : null}
      {showWrap ? <CodeBlockWrapButton /> : null}
      {showDownload ? <CodeBlockDownloadButton /> : null}
      {showExpand ? <CodeBlockExpandButton /> : null}
      {showCopy ? <CodeBlockCopyButton /> : null}
    </div>
  );
}

"use client";
import { cn } from "@/lib/utils";

export interface CodeBlockFilenameProps {
  filename?: string;
  className?: string;
}

export function CodeBlockFilename({ filename, className }: CodeBlockFilenameProps) {
  if (!filename) return null;
  return (
    <span
      className={cn(
        "font-mono text-[0.78rem] text-foreground/85 tracking-tight",
        className,
      )}
    >
      {filename}
    </span>
  );
}

"use client";
import { cn } from "@/lib/utils";

export interface CodeBlockLangPillProps {
  lang: string;
  className?: string;
}

export function CodeBlockLangPill({ lang, className }: CodeBlockLangPillProps) {
  if (!lang || lang === "plaintext") return null;
  return (
    <span
      className={cn(
        "font-mono text-[0.7rem] uppercase tracking-wider text-muted-foreground/80",
        className,
      )}
    >
      {lang}
    </span>
  );
}

"use client";
import { Check, Copy, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useCodeBlock } from "../hooks/use-code-block-context";

export interface CodeBlockCopyButtonProps {
  className?: string;
}

export function CodeBlockCopyButton({ className }: CodeBlockCopyButtonProps) {
  const { copy, copied, copyFailed, labels } = useCodeBlock();

  const Icon = copyFailed ? X : copied ? Check : Copy;
  const label = copyFailed ? labels.copyFailed : copied ? labels.copied : labels.copy;

  return (
    <>
      <Button
        type="button"
        size="icon"
        variant="ghost"
        className={cn("size-7 text-muted-foreground hover:text-foreground", className)}
        onClick={() => void copy()}
        aria-label={label}
        title={label}
      >
        <Icon className="size-3.5" aria-hidden="true" />
      </Button>
      {/* Screen-reader-only status. role="status" with aria-live="polite" so
          the SR announces "Copied" after the icon swap. */}
      <span role="status" aria-live="polite" className="sr-only">
        {copied ? labels.copied : copyFailed ? labels.copyFailed : ""}
      </span>
    </>
  );
}

"use client";
import { Maximize2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useCodeBlock } from "../hooks/use-code-block-context";

export interface CodeBlockExpandButtonProps {
  className?: string;
}

export function CodeBlockExpandButton({ className }: CodeBlockExpandButtonProps) {
  const { setModalOpen, labels } = useCodeBlock();

  return (
    <Button
      type="button"
      size="icon"
      variant="ghost"
      className={cn("size-7 text-muted-foreground hover:text-foreground", className)}
      onClick={() => setModalOpen(true)}
      aria-label={labels.expand}
      title={labels.expand}
    >
      <Maximize2 className="size-3.5" aria-hidden="true" />
    </Button>
  );
}

"use client";
import { WrapText } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useCodeBlock } from "../hooks/use-code-block-context";

export interface CodeBlockWrapButtonProps {
  className?: string;
}

export function CodeBlockWrapButton({ className }: CodeBlockWrapButtonProps) {
  const { wrap, setWrap, labels } = useCodeBlock();
  const isWrapped = wrap === "wrap";

  return (
    <Button
      type="button"
      size="icon"
      variant="ghost"
      className={cn(
        "size-7 text-muted-foreground hover:text-foreground",
        isWrapped && "text-foreground",
        className,
      )}
      onClick={() => setWrap(isWrapped ? "scroll" : "wrap")}
      aria-label={labels.wrap}
      aria-pressed={isWrapped}
      title={labels.wrap}
    >
      <WrapText className="size-3.5" aria-hidden="true" />
    </Button>
  );
}

"use client";
import { Download } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useCodeBlock } from "../hooks/use-code-block-context";

export interface CodeBlockDownloadButtonProps {
  className?: string;
}

export function CodeBlockDownloadButton({ className }: CodeBlockDownloadButtonProps) {
  const { download, labels } = useCodeBlock();

  return (
    <Button
      type="button"
      size="icon"
      variant="ghost"
      className={cn("size-7 text-muted-foreground hover:text-foreground", className)}
      onClick={download}
      aria-label={labels.download}
      title={labels.download}
    >
      <Download className="size-3.5" aria-hidden="true" />
    </Button>
  );
}

"use client";
import { cn } from "@/lib/utils";

export interface CodeBlockTrafficLightsProps {
  className?: string;
}

/**
 * macOS-style traffic-light decoration (three muted circles).
 * Purely presentational — no behaviour. Opt-in via the `showTrafficLights`
 * prop on `<CodeBlock>`, or compose manually inside `renderHeader`.
 */
export function CodeBlockTrafficLights({ className }: CodeBlockTrafficLightsProps) {
  return (
    <div
      aria-hidden="true"
      className={cn("flex items-center gap-1.5", className)}
    >
      <span className="block size-3 rounded-full bg-[oklch(0.78_0.16_25)] opacity-70" />
      <span className="block size-3 rounded-full bg-[oklch(0.84_0.15_85)] opacity-70" />
