"use client";
import { useCallback, useEffect, useRef, useState } from "react";

interface UseControllableStateArgs<T> {
  prop: T | undefined;
  defaultProp: T;
  onChange?: (value: T) => void;
}

/**
 * Standard controlled/uncontrolled state helper. When `prop` is defined it
 * is treated as the source of truth (controlled); otherwise component state
 * is used (uncontrolled). `onChange` always fires.
 */
export function useControllableState<T>({
  prop,
  defaultProp,
  onChange,
}: UseControllableStateArgs<T>): [T, (next: T) => void] {
  const [uncontrolledValue, setUncontrolledValue] = useState<T>(defaultProp);
  const isControlled = prop !== undefined;
  const value = isControlled ? prop : uncontrolledValue;

  const onChangeRef = useRef(onChange);
  useEffect(() => {
    onChangeRef.current = onChange;
  }, [onChange]);

  const setValue = useCallback(
    (next: T) => {
      if (!isControlled) {
        setUncontrolledValue(next);
      }
      onChangeRef.current?.(next);
    },
    [isControlled],
  );

  return [value, setValue];
}

"use client";
import { useCallback, useRef, useState } from "react";

interface UseCopyToClipboardResult {
  copy: (text: string) => Promise<boolean>;
  copied: boolean;
  failed: boolean;
}

/**
 * Clipboard write with legacy `document.execCommand('copy')` fallback for
 * browsers without the async Clipboard API. Returns transient `copied` /
 * `failed` flags that auto-clear after `revertMs` for icon-swap UX.
 */
export function useCopyToClipboard(revertMs = 1500): UseCopyToClipboardResult {
  const [copied, setCopied] = useState(false);
  const [failed, setFailed] = useState(false);
  const timeoutRef = useRef<number | null>(null);

  const reset = useCallback(() => {
    if (timeoutRef.current !== null) {
      window.clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    timeoutRef.current = window.setTimeout(() => {
      setCopied(false);
      setFailed(false);
      timeoutRef.current = null;
    }, revertMs);
  }, [revertMs]);

  const copy = useCallback(
    async (text: string): Promise<boolean> => {
      let ok = false;
      try {
        if (
          typeof navigator !== "undefined" &&
          navigator.clipboard &&
          typeof navigator.clipboard.writeText === "function"
        ) {
          await navigator.clipboard.writeText(text);
          ok = true;
        }
      } catch {
        ok = false;
      }
      if (!ok && typeof document !== "undefined") {
        try {
          const ta = document.createElement("textarea");
          ta.value = text;
          ta.style.position = "fixed";
          ta.style.left = "-9999px";
          ta.setAttribute("readonly", "");
          document.body.appendChild(ta);
          ta.select();
          ok = document.execCommand("copy");
          document.body.removeChild(ta);
        } catch {
          ok = false;
        }
      }
      if (ok) {
        setCopied(true);
        setFailed(false);
      } else {
        setCopied(false);
        setFailed(true);
      }
      reset();
      return ok;
    },
    [reset],
  );

  return { copy, copied, failed };
}

"use client";
import { useEffect, useRef, useState } from "react";
import type { HighlighterCore } from "shiki/core";
import {
  DEFAULT_THEME_NAMES,
  ensureLangLoaded,
  ensureThemeLoaded,
  getHighlighter,
  normalizeLang,
} from "../lib/shiki-bundle";
import { rangeToLines } from "../lib/line-utils";
import {
  diffForRetokenize,
  emptyCache,
  type StreamingCache,
} from "../lib/streaming-cache";
import type { CodeBlockLineRange, CodeBlockThemes } from "../types";

interface UseShikiHighlighterArgs {
  value: string;
  lang: string;
  themes: CodeBlockThemes | undefined;
  highlightedLines?: Array<number | CodeBlockLineRange>;
  streaming?: boolean;
}

interface UseShikiHighlighterResult {
  html: string;
  ready: boolean;
  resolvedLang: string;
}

function resolveThemeName(
  themes: CodeBlockThemes | undefined,
  variant: "light" | "dark",
): string {
  const entry = themes?.[variant];
  if (!entry) return DEFAULT_THEME_NAMES[variant];
  if (typeof entry === "string") return entry;
  return entry.name;
}

function highlight(
  highlighter: HighlighterCore,
  value: string,
  lang: string,
  lightTheme: string,
  darkTheme: string,
  highlightedSet: Set<number>,
): string {
  const html = highlighter.codeToHtml(value, {
    lang,
    themes: { light: lightTheme, dark: darkTheme },
    defaultColor: false,
    cssVariablePrefix: "--shiki-",
    transformers: [
      {
        name: "code-block-highlighted-lines",
        line(node, lineNumber) {
          if (highlightedSet.has(lineNumber)) {
            node.properties = node.properties ?? {};
            node.properties["data-highlighted"] = "true";
          }
        },
      },
    ],
  });
  return html;
}

export function useShikiHighlighter({
  value,
  lang,
  themes,
  highlightedLines,
  streaming,
}: UseShikiHighlighterArgs): UseShikiHighlighterResult {
  const [html, setHtml] = useState<string>("");
  const [ready, setReady] = useState(false);
  const [resolvedLang, setResolvedLang] = useState<string>(normalizeLang(lang));
  const cacheRef = useRef<StreamingCache>(emptyCache());
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    let cancelled = false;
    const lightTheme = resolveThemeName(themes, "light");
    const darkTheme = resolveThemeName(themes, "dark");
    const highlightedSet = rangeToLines(highlightedLines);

    const run = async () => {
      const highlighter = await getHighlighter();
      if (cancelled) return;
      const langForRender = await ensureLangLoaded(highlighter, lang);
      if (cancelled) return;
      await Promise.all([
        ensureThemeLoaded(highlighter, lightTheme),
        ensureThemeLoaded(highlighter, darkTheme),
      ]);
      if (cancelled) return;
      setResolvedLang(langForRender);

      // v0.1.0 streaming strategy: full re-tokenize per update, but batched
      // to a single rAF (suppresses thrash from rapid char-level updates).
      // Shiki caches grammars + themes, so warm-state tokenization is cheap
      // (<5 ms for typical view-mode blocks). Pure append-only diff path
      // is locked at lib/streaming-cache.ts and wired in for v0.2.
      const full = highlight(
        highlighter,
        value,
        langForRender,
        lightTheme,
        darkTheme,
        highlightedSet,
      );
      if (streaming) {
        // Surface the cache helper so it isn't tree-shaken; v0.2 will diff
        // against it for the pure append optimisation.
        diffForRetokenize(cacheRef.current, value);
      }
      cacheRef.current = { prevValue: value, prevHtmlLines: [full] };
      if (!cancelled) setHtml(full);
      if (!cancelled) setReady(true);
    };

    if (rafRef.current !== null) {
      cancelAnimationFrame(rafRef.current);
    }
    rafRef.current = requestAnimationFrame(() => {
      void run();
    });

    return () => {
      cancelled = true;
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
    };
  }, [value, lang, themes, highlightedLines, streaming]);

  return { html, ready, resolvedLang };
}

"use client";
import { useCallback, useEffect, useRef, useState } from "react";
import { Compartment, EditorState, type Extension } from "@codemirror/state";
import { EditorView, keymap, lineNumbers as cmLineNumbers } from "@codemirror/view";
import {
  defaultKeymap,
  history,
  historyKeymap,
  indentLess,
  indentMore,
} from "@codemirror/commands";
import { bracketMatching, indentOnInput } from "@codemirror/language";
import { closeBrackets, closeBracketsKeymap } from "@codemirror/autocomplete";
import { buildCodeMirrorTheme } from "../lib/codemirror-theme";
import { loadCodeMirrorLang } from "../lib/codemirror-langs";
import { normalizeLang } from "../lib/shiki-bundle";

interface UseCodeMirrorArgs {
  value: string;
  lang: string;
  readOnly: boolean;
  wrap: "wrap" | "scroll";
  tabSize: number;
  showLineNumbers: boolean;
  onChange?: (value: string) => void;
  onSave?: (value: string) => void;
  editorExtensions?: Extension[];
}

interface UseCodeMirrorResult {
  containerRef: React.RefObject<HTMLDivElement | null>;
  view: EditorView | null;
  focus: () => void;
  getValue: () => string;
}

export function useCodeMirror({
  value,
  lang,
  readOnly,
  wrap,
  tabSize,
  showLineNumbers,
  onChange,
  onSave,
  editorExtensions,
}: UseCodeMirrorArgs): UseCodeMirrorResult {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const viewRef = useRef<EditorView | null>(null);
  const wrapCompartmentRef = useRef(new Compartment());
  const langCompartmentRef = useRef(new Compartment());
  const readOnlyCompartmentRef = useRef(new Compartment());

  // Refs for callbacks so the editor doesn't remount on identity changes.
  // Synced via useEffect to avoid setting refs during render (React 19 rule).
  const onChangeRef = useRef(onChange);
  const onSaveRef = useRef(onSave);
  useEffect(() => {
    onChangeRef.current = onChange;
  }, [onChange]);
  useEffect(() => {
    onSaveRef.current = onSave;
  }, [onSave]);

  const [view, setView] = useState<EditorView | null>(null);

  // Mount (once per container)
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    let cancelled = false;

    const mount = async () => {
      const normalizedLang = normalizeLang(lang);
      const langExt = (await loadCodeMirrorLang(normalizedLang)) ?? [];
      if (cancelled) return;

      const extensions: Extension[] = [
        history(),
        bracketMatching(),
        indentOnInput(),
        closeBrackets(),
        keymap.of([
          ...defaultKeymap,
          ...historyKeymap,
          ...closeBracketsKeymap,
          { key: "Tab", run: indentMore, shift: indentLess },
          {
            key: "Mod-s",
            preventDefault: true,
            run: (v) => {
              const text = v.state.doc.toString();
              if (onSaveRef.current) {
                onSaveRef.current(text);
              } else if (process.env.NODE_ENV !== "production") {
                console.warn(
                  "[CodeBlock] Cmd+S pressed in edit mode but `onSave` is not wired — no-op.",
                );
              }
              return true;
            },
          },
        ]),
        EditorState.tabSize.of(tabSize),
        EditorState.allowMultipleSelections.of(true),
        wrapCompartmentRef.current.of(wrap === "wrap" ? EditorView.lineWrapping : []),
        langCompartmentRef.current.of(langExt),
        readOnlyCompartmentRef.current.of([
          EditorView.editable.of(!readOnly),
          EditorState.readOnly.of(readOnly),
        ]),
        ...(showLineNumbers ? [cmLineNumbers()] : []),
        EditorView.updateListener.of((u) => {
          if (u.docChanged) {
            onChangeRef.current?.(u.state.doc.toString());
          }
        }),
        buildCodeMirrorTheme(),
        ...(editorExtensions ?? []),
      ];

      const v = new EditorView({
        state: EditorState.create({ doc: value, extensions }),
        parent: container,
      });
      viewRef.current = v;
      if (!cancelled) setView(v);
    };

    void mount();
    return () => {
      cancelled = true;
      viewRef.current?.destroy();
      viewRef.current = null;
      setView(null);
    };
    // Intentionally only depend on `showLineNumbers` for mount — value sync
    // happens in its own effect below.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showLineNumbers]);

  // Controlled value sync
  useEffect(() => {
    const v = viewRef.current;
    if (!v) return;
    const current = v.state.doc.toString();
    if (current === value) return;
    v.dispatch({
      changes: { from: 0, to: current.length, insert: value },
    });
  }, [value]);

  // Wrap reconfigure
  useEffect(() => {
    const v = viewRef.current;
    if (!v) return;
    v.dispatch({
      effects: wrapCompartmentRef.current.reconfigure(
        wrap === "wrap" ? EditorView.lineWrapping : [],
      ),
    });
  }, [wrap]);

  // Lang reconfigure (async — load lang package on change)
  useEffect(() => {
    const v = viewRef.current;
    if (!v) return;
    let cancelled = false;
    const apply = async () => {
      const normalizedLang = normalizeLang(lang);
      const langExt = (await loadCodeMirrorLang(normalizedLang)) ?? [];
      if (cancelled || !viewRef.current) return;
      viewRef.current.dispatch({
        effects: langCompartmentRef.current.reconfigure(langExt),
      });
    };
    void apply();
    return () => {
      cancelled = true;
    };
  }, [lang]);

  // Read-only reconfigure
  useEffect(() => {
    const v = viewRef.current;
    if (!v) return;
    v.dispatch({
      effects: readOnlyCompartmentRef.current.reconfigure([
        EditorView.editable.of(!readOnly),
        EditorState.readOnly.of(readOnly),
      ]),
    });
  }, [readOnly]);

  const focus = useCallback(() => viewRef.current?.focus(), []);
  const getValue = useCallback(
    () => viewRef.current?.state.doc.toString() ?? "",
    [],
  );

  return { containerRef, view, focus, getValue };
}

"use client";
import { useEffect, useState } from "react";

function readInitialIsDark(): boolean {
  if (typeof document === "undefined") return false;
  return document.documentElement.classList.contains("dark");
}

/**
 * Observes the document's `.dark` class. Used informationally only —
 * the actual palette swap happens via CSS variables on the
 * `.code-block-editor` host element. Useful for assistive-tech
 * announcements or `aria-` attributes that need the resolved theme.
 */
export function useResolvedTheme(): "light" | "dark" {
  const [isDark, setIsDark] = useState<boolean>(readInitialIsDark);

  useEffect(() => {
    if (typeof document === "undefined") return;
    const root = document.documentElement;
    const observer = new MutationObserver(() => {
      setIsDark(root.classList.contains("dark"));
    });
    observer.observe(root, { attributes: true, attributeFilter: ["class"] });
    return () => observer.disconnect();
  }, []);

  return isDark ? "dark" : "light";
}

