  log: "plaintext",
};

const FILENAME_OVERRIDES: Record<string, string> = {
  dockerfile: "dockerfile",
  makefile: "makefile",
};

export function resolveLang(
  lang: string | undefined,
  filename: string | undefined,
  override: ((args: CodeBlockFilenameToLangArgs) => string | undefined) | undefined,
): string {
  if (lang) return lang;
  if (!filename) return "plaintext";

  const lowered = filename.toLowerCase();
  const exact = FILENAME_OVERRIDES[lowered];
  if (exact) return exact;

  if (override) {
    const overridden = override({ filename });
    if (overridden) return overridden;
  }

  const ext = filename.split(".").pop()?.toLowerCase() ?? "";
  return FILENAME_TO_LANG_MAP[ext] ?? "plaintext";
}

import type { CodeBlockLineRange } from "../types";

export function splitToLines(value: string): string[] {
  if (value === "") return [];
  return value.split("\n");
}

export function lineCount(value: string): number {
  if (value === "") return 0;
  return value.split("\n").length;
}

export function rangeToLines(
  highlighted: Array<number | CodeBlockLineRange> | undefined,
): Set<number> {
  const out = new Set<number>();
  if (!highlighted) return out;
  for (const entry of highlighted) {
    if (typeof entry === "number") {
      if (entry > 0) out.add(entry);
      continue;
    }
    const { from, to } = entry;
    const start = Math.max(1, Math.min(from, to));
    const end = Math.max(from, to);
    for (let i = start; i <= end; i++) out.add(i);
  }
  return out;
}

export function gutterWidth(totalLines: number): number {
  if (totalLines < 10) return 1;
  if (totalLines < 100) return 2;
  if (totalLines < 1000) return 3;
  return 4;
}

import type { TerminalLine, TerminalLineKind } from "../types";

const PROMPT_PATTERNS = ["$ ", "> ", "# "] as const;

export function promptDetect(line: string): TerminalLineKind {
  for (const p of PROMPT_PATTERNS) {
    if (line.startsWith(p)) return "input";
  }
  return "output";
}

export function parseTerminalLines(value: string): TerminalLine[] {
  if (value === "") return [];
  return value.split("\n").map((text) => ({ kind: promptDetect(text), text }));
}

export function promptPrefix(text: string): { prefix: string; rest: string } {
  for (const p of PROMPT_PATTERNS) {
    if (text.startsWith(p)) {
      return { prefix: p, rest: text.slice(p.length) };
    }
  }
  return { prefix: "", rest: text };
}

export function joinTerminalLines(lines: TerminalLine[]): string {
  return lines.map((l) => l.text).join("\n");
}

/**
 * Shiki bundle setup with fine-grained imports + on-demand grammar loading.
 *
 * Default ships ~10 common grammars synchronously (ts/tsx/js/jsx/json/python/
 * bash/markdown/html/css). Other grammars dynamic-import on first use.
 *
 * Themes default to GitHub Light + GitHub Dark Default (small, sync-loaded).
 */
import {
  createHighlighterCore,
  type HighlighterCore,
  type LanguageRegistration,
  type ThemeRegistrationAny,
} from "shiki/core";
import { createOnigurumaEngine } from "shiki/engine/oniguruma";

let cachedHighlighter: Promise<HighlighterCore> | null = null;
const loadedLangs = new Set<string>();

const LAZY_LANG_LOADERS: Record<string, () => Promise<unknown>> = {
  rust: () => import("shiki/langs/rust.mjs"),
  go: () => import("shiki/langs/go.mjs"),
  sql: () => import("shiki/langs/sql.mjs"),
  yaml: () => import("shiki/langs/yaml.mjs"),
  diff: () => import("shiki/langs/diff.mjs"),
  java: () => import("shiki/langs/java.mjs"),
  c: () => import("shiki/langs/c.mjs"),
  cpp: () => import("shiki/langs/cpp.mjs"),
  csharp: () => import("shiki/langs/csharp.mjs"),
  ruby: () => import("shiki/langs/ruby.mjs"),
  php: () => import("shiki/langs/php.mjs"),
  swift: () => import("shiki/langs/swift.mjs"),
  kotlin: () => import("shiki/langs/kotlin.mjs"),
  graphql: () => import("shiki/langs/graphql.mjs"),
  toml: () => import("shiki/langs/toml.mjs"),
  ini: () => import("shiki/langs/ini.mjs"),
  scss: () => import("shiki/langs/scss.mjs"),
  dockerfile: () => import("shiki/langs/dockerfile.mjs"),
  makefile: () => import("shiki/langs/makefile.mjs"),
  patch: () => import("shiki/langs/diff.mjs"),
};

const LANG_ALIASES: Record<string, string> = {
  javascript: "js",
  typescript: "ts",
  py: "python",
  rb: "ruby",
  rs: "rust",
  yml: "yaml",
  sh: "bash",
  zsh: "bash",
  md: "markdown",
  mdx: "markdown",
};

export function normalizeLang(lang: string | undefined): string {
  if (!lang) return "plaintext";
  const lower = lang.toLowerCase();
  return LANG_ALIASES[lower] ?? lower;
}

async function loadCoreGrammars(): Promise<LanguageRegistration[]> {
  const [ts, tsx, js, jsx, json, bash, python, markdown, html, css] = await Promise.all([
    import("shiki/langs/ts.mjs"),
    import("shiki/langs/tsx.mjs"),
    import("shiki/langs/javascript.mjs"),
    import("shiki/langs/jsx.mjs"),
    import("shiki/langs/json.mjs"),
    import("shiki/langs/bash.mjs"),
    import("shiki/langs/python.mjs"),
    import("shiki/langs/markdown.mjs"),
    import("shiki/langs/html.mjs"),
    import("shiki/langs/css.mjs"),
  ]);
  const out = [ts, tsx, js, jsx, json, bash, python, markdown, html, css]
    .map((m) => (m as { default: unknown }).default)
    .flat() as LanguageRegistration[];
  for (const reg of out) {
    if (reg && typeof reg === "object" && "name" in reg && typeof reg.name === "string") {
      loadedLangs.add(reg.name);
    }
  }
  return out;
}

async function loadCoreThemes(): Promise<ThemeRegistrationAny[]> {
  const [light, dark] = await Promise.all([
    import("shiki/themes/github-light.mjs"),
    import("shiki/themes/github-dark-default.mjs"),
  ]);
  return [
    (light as { default: ThemeRegistrationAny }).default,
    (dark as { default: ThemeRegistrationAny }).default,
  ];
}

export function getHighlighter(): Promise<HighlighterCore> {
  if (cachedHighlighter) return cachedHighlighter;
  cachedHighlighter = (async () => {
    const [langs, themes, wasmMod] = await Promise.all([
      loadCoreGrammars(),
      loadCoreThemes(),
      import("shiki/wasm"),
    ]);
    // shiki/wasm exports the wasm-loader function as `default`.
    const wasm = wasmMod.default;
    return createHighlighterCore({
      engine: createOnigurumaEngine(wasm),
      langs,
      themes,
    });
  })();
  return cachedHighlighter;
}

export async function ensureLangLoaded(
  highlighter: HighlighterCore,
  lang: string,
): Promise<string> {
  const normalized = normalizeLang(lang);
  if (normalized === "plaintext") return normalized;
  if (loadedLangs.has(normalized)) return normalized;
  if (highlighter.getLoadedLanguages().includes(normalized)) {
    loadedLangs.add(normalized);
    return normalized;
  }
  const loader = LAZY_LANG_LOADERS[normalized];
  if (!loader) {
    if (process.env.NODE_ENV !== "production") {
      console.warn(`[CodeBlock] Unknown lang "${lang}" — falling back to plaintext.`);
    }
    return "plaintext";
  }
  const mod = (await loader()) as { default: LanguageRegistration | LanguageRegistration[] };
  const reg = Array.isArray(mod.default) ? mod.default : [mod.default];
  await highlighter.loadLanguage(...reg);
  loadedLangs.add(normalized);
  return normalized;
}

export async function ensureThemeLoaded(
  highlighter: HighlighterCore,
  themeName: string,
): Promise<void> {
  if (highlighter.getLoadedThemes().includes(themeName)) return;
  // Attempt dynamic import from shiki/themes/<name>.mjs
  try {
    const mod = (await import(/* @vite-ignore */ `shiki/themes/${themeName}.mjs`)) as {
      default: ThemeRegistrationAny;
    };
    await highlighter.loadTheme(mod.default);
  } catch {
    if (process.env.NODE_ENV !== "production") {
      console.warn(`[CodeBlock] Theme "${themeName}" not found in shiki/themes/.`);
    }
  }
}

export const DEFAULT_THEME_NAMES = {
  light: "github-light",
  dark: "github-dark-default",
} as const;

import type { Extension } from "@codemirror/state";
import { normalizeLang } from "./shiki-bundle";

type LangLoader = () => Promise<Extension | null>;

const CM_LANG_LOADERS: Record<string, LangLoader> = {
  ts: async () =>
    (await import("@codemirror/lang-javascript")).javascript({
      typescript: true,
      jsx: false,
    }),
  tsx: async () =>
    (await import("@codemirror/lang-javascript")).javascript({
      typescript: true,
      jsx: true,
    }),
  js: async () =>
    (await import("@codemirror/lang-javascript")).javascript({ jsx: false }),
  jsx: async () =>
    (await import("@codemirror/lang-javascript")).javascript({ jsx: true }),
  json: async () => (await import("@codemirror/lang-json")).json(),
  python: async () => (await import("@codemirror/lang-python")).python(),
  html: async () => (await import("@codemirror/lang-html")).html(),
  css: async () => (await import("@codemirror/lang-css")).css(),
  markdown: async () => (await import("@codemirror/lang-markdown")).markdown(),
};

export async function loadCodeMirrorLang(
  lang: string,
): Promise<Extension | null> {
  const normalized = normalizeLang(lang);
  const loader = CM_LANG_LOADERS[normalized];
  if (!loader) return null;
  try {
    return await loader();
  } catch (err) {
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        `[CodeBlock] CodeMirror lang package for "${lang}" failed to load:`,
        err,
      );
    }
    return null;
  }
}

